@app.route('/login')
def login():
    client_config_key = request.args.get('client_config_key', 'default')
    redirect_uri_from_client = request.args.get('redirect_uri')

    config = CLIENT_CONFIGS.get(client_config_key)
    if not config:
        return "Client configuration not found.", 400

    configured_domain = config['configured_domain']

    if not redirect_uri_from_client:
        return "redirect_uri parameter is required.", 400

    # --- Redirect URI Validation ---
    # Check if the redirect_uri contains the configured domain string.
    # This allows for subdomains and different paths under the main domain.
    if configured_domain not in redirect_uri_from_client:
        return f"Invalid redirect_uri. Must contain '{configured_domain}'.", 400

    # Store the validated redirect_uri in the session to retrieve after callback
    session['redirect_uri_after_callback'] = redirect_uri_from_client

    # Register the OAuth client dynamically for this request
    my_oauth_provider = register_oauth_client(
        config['client_id'],
        config['client_secret'],
        config['authorize_url'],
        config['token_url']
    )

    # Note: Flask-OAuthlib or Authlib expects the redirect_uri to be passed
    # as an argument to authorize(). It will then use this URI to construct the
    # authorization request. The provider *must* have this URI (or its domain) pre-registered.
    return my_oauth_provider.authorize_redirect(
        redirect_uri_from_client, # Use the validated redirect_uri
        scope=config['scope']
    )

@app.route('/auth_callback')
def auth_callback():
    # This route will receive the authorization response from the OAuth provider.
    # The actual redirect_uri used here MUST match what was sent in the /authorize request.
    # Flask-OAuthlib/Authlib handles this automatically if you pass the same URI.

    # Retrieve the stored redirect_uri from the session. This is the URI
    # our client requested to be redirected to after the OAuth flow.
    # This will be validated by the OAuth provider.
    redirect_uri_for_token_exchange = session.pop('redirect_uri_after_callback', None)
    if not redirect_uri_for_token_exchange:
        return "Missing redirect_uri in session. Cannot complete flow.", 400

    # Re-register the OAuth client using a default or inferred config for callback processing.
    # In a real multi-tenant app, you'd need to identify which tenant/client config
    # this callback belongs to (e.g., from a state parameter or subdomain).
    # For simplicity, we'll use the 'default' config here, assuming it's the one that initiated the flow.
    config = CLIENT_CONFIGS['default'] # Adjust this to dynamically select the correct config
    my_oauth_provider = register_oauth_client(
        config['client_id'],
        config['client_secret'],
        config['authorize_url'],
        config['token_url']
    )

    try:
        # Exchange authorization code for tokens
        token = my_oauth_provider.authorize_access_token(
            redirect_uri=redirect_uri_for_token_exchange # Crucial: Pass the same redirect_uri
        )
        session['token'] = token

        # Fetch user info if configured
        user_info = None
        if config.get('userinfo_url'):
            resp = my_oauth_provider.get(config['userinfo_url'])
            resp.raise_for_status()
            user_info = resp.json()
            session['user_info'] = user_info

        # Redirect the user back to the originally requested 'redirect_uri_after_callback'
        # with any necessary parameters (e.g., a session token, user info, etc.)
        # For simplicity, we'll just redirect to a success page for now.
        return redirect(url_for('success'))

    except Exception as e:
        return f"OAuth callback failed: {e}", 500

@app.route('/success')
def success():
    user_info = session.get('user_info', {})
    token = session.get('token', {})
    return jsonify({
        'message': 'Successfully logged in!',
        'user': user_info.get('name', user_info.get('email', 'Unknown User')),
        'access_token_present': 'access_token' in token
    })

@app.route('/logout')
def logout():
    session.pop('token', None)
    session.pop('user_info', None)
    session.pop('redirect_uri_after_callback', None)
    return redirect(url_for('index'))

